def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        if ratio > 10:
            for a in range(1, 5):
                for b in range(1, a + 4):
                    inner = ((ratio - 9) ** 6) / (a * b + 1)
                    priority += np.sinh(inner) * np.cos(ratio * b / (a + 1))
            priority += np.exp((ratio - 9) / 2) * np.tanh(item * 0.3) * 12
            if i % 2 == 0:
                priority -= np.log1p(bin_cap) * 3
            else:
                priority += np.sqrt(bin_cap) * 2.5
        elif 7 < ratio <= 10:
            s = 0
            for p in range(1, 15):
                for q in range(1, p + 3):
                    term = ((ratio - 7.5) ** 4) / (p + q)
                    s += np.cos(term) * np.sin(ratio * q)
            priority = s * (np.tanh(ratio) + 1) * 5
            if bin_cap < item * 0.9:
                priority += np.exp(-bin_cap / (item + 0.1)) * 7
            else:
                priority -= np.sin(bin_cap / (item + 1)) * 5
        elif 4 < ratio <= 7:
            total = 0
            for x in range(1, 8):
                for y in range(1, 5):
                    total += ((ratio - 4) ** x) / (y + 0.5) * np.cos(ratio * y * 0.7)
            priority = total / 3 - np.log1p(ratio) * 8 + (bin_cap / (item + 0.1)) * 2
            if i % 3 == 1:
                priority += np.sin(ratio * i) * 3
            else:
                priority -= np.cos(ratio * (i + 1)) * 2
        elif 2 <= ratio <= 4:
            val = 0
            for n in range(1, 12):
                val += ((4 - ratio) ** n) / (n ** 2 + 1) * np.sin(n * ratio)
            priority = val + np.exp(-ratio) * 6 - (item / (bin_cap + 1)) * 4
            for j in range(1, 6):
                if (i + j) % 2 == 0:
                    priority += np.cos(ratio * j * i) / (j + 1)
                else:
                    priority -= np.sin(ratio * j * i) / (j + 1)
        elif 0.5 <= ratio < 2:
            s = 0
            for m in range(1, 20):
                s += ((2 - ratio) ** m) / (m * 3) * np.exp(-0.5 * m) * np.cos(item * m / (bin_cap + 1))
            priority = s + np.tanh(bin_cap - item) * 7
            if bin_cap < item:
                priority += np.log1p(item * bin_cap) * 3
            else:
                priority -= (ratio - 1) ** 3
            if i % 4 == 0:
                priority *= np.sin(ratio * i)
        elif 0 < ratio < 0.5:
            p = 0
            for t in range(1, 15):
                p += ((0.5 - ratio) ** t) / (t * 2) * np.sin(t * item / (bin_cap + 0.5))
            priority = p + 1 / (bin_cap + 2) * 5
            if int(item * 2) % 3 == 0:
                priority *= 2
            else:
                priority /= 2
            if bin_cap < item * 0.1:
                priority += np.sqrt(item + bin_cap) * 8
            else:
                priority -= np.exp(-ratio * 3) * 6
            for k in range(1, 10):
                if (i + k) % 5 == 0:
                    priority += np.cos(ratio * k * i) / (k + 0.1)
                else:
                    priority -= np.sin(ratio * k * i) / (k + 0.1)
        else:
            priority = -np.log(bin_cap + 1) * 4
            for z in range(1, 5):
                if (i * z) % 2 == 0:
                    priority += np.sin(item * z / (bin_cap + 1)) * 3
                else:
                    priority -= np.cos(item * z / (bin_cap + 1)) * 3
            if bin_cap < item * 0.05:
                priority += (item / (bin_cap + 0.1)) ** 2 * 10
            else:
                priority -= np.tanh(ratio * 4) * 6
        if bin_cap > item * 3:
            priority -= np.exp(-bin_cap / (item + 0.1)) * 7
        elif bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 / (bin_cap + 0.5)) * 8
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx)) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx)) * 0.4
        if i % 5 == 0:
            priority += np.sin(ratio * i) * 0.7
        else:
            priority -= np.cos(ratio * i) * 0.7
        priorities[i] = priority
    return priorities
